static common_chat_params common_chat_params_init_mistral_instruct_v3(
    const common_chat_template &          tmpl,
    const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Collect the system message (if any) to prepend to the first user turn
    std::string system_message;
    for (const auto & msg : inputs.messages) {
        if (msg.value("role", "") == "system") {
            system_message = msg.value("content", "");
            break;
        }
    }

    // Build the prompt by iterating messages
    bool first_user = true;
    for (const auto & msg : inputs.messages) {
        const auto role    = msg.value("role", "");
        const auto content = msg.value("content", "");

        if (role == "system") {
            continue;  // already captured above
        } else if (role == "user") {
            if (first_user) {
                // <s>[INST] {system\n}{user} [/INST]
                data.prompt += "<s>[INST] ";
                if (!system_message.empty()) {
                    data.prompt += system_message + "\n";
                }
                data.prompt += content + " [/INST]";
                first_user = false;
            } else {
                // Subsequent turns: no leading <s>
                data.prompt += "[INST] " + content + " [/INST]";
            }
        } else if (role == "assistant") {
            data.prompt += " " + content + "</s>";
        }
    }

    data.format = COMMON_CHAT_FORMAT_CONTENT_ONLY;
    return data;
}

